const triggerJson = $('Google Drive Trigger').item.json;

// MED-2: sanitize fileName and mimeType before use in any log/error message
const fileName = String(triggerJson.name || '').replace(/[\x00-\x1F\x7F]/g, '').slice(0, 255);
const mimeType = String(triggerJson.mimeType || '').replace(/[\x00-\x1F\x7F]/g, '').slice(0, 255);
const fileId   = String(triggerJson.id   || '').replace(/[^A-Za-z0-9_\-]/g, '').slice(0, 128);

// F-04.2 stub: audio not yet supported (SC-10 compliant endpoint required first)
const AUDIO_MIMES = ['audio/mpeg', 'audio/mp4', 'audio/wav', 'audio/x-wav', 'audio/x-m4a'];
if (AUDIO_MIMES.includes(mimeType) || /\.(mp3|m4a|wav)$/i.test(fileName)) {
  throw new Error(
    'F-04.2 NOT IMPLEMENTED: Audio transcription requires an in-house SC-10-compliant transcription endpoint. ' +
    'fileName=[sanitized]'
  );
}

// F-04.5: reject unsupported formats
const TEXT_MIMES = [
  'text/plain', 'text/markdown', 'text/csv',
  'application/vnd.google-apps.document',
  'application/vnd.openxmlformats-officedocument.wordprocessingml.document'
];
const TEXT_EXTS = ['.txt', '.md', '.csv', '.docx'];
const ext = fileName.toLowerCase().slice(fileName.lastIndexOf('.'));
const isText = TEXT_MIMES.includes(mimeType) || TEXT_EXTS.includes(ext);

if (!isText) {
  throw new Error(
    'F-04.5: Unsupported file format — skipping. ' +
    'ext=' + ext + ' mimeType=' + mimeType
  );
}

// Decode binary content from Google Drive download node
const binaryProperty = $input.first().binary;
let rawText = '';
if (binaryProperty && binaryProperty.data) {
  const buf = binaryProperty.data.data || binaryProperty.data;
  rawText = Buffer.isBuffer(buf)
    ? buf.toString('utf-8')
    : Buffer.from(buf, 'base64').toString('utf-8');
} else if ($json.text) {
  rawText = String($json.text);
}

if (!rawText.trim()) {
  throw new Error('F-04: Transcript is empty after decoding.');
}

// SC-14: strip n8n expression injection delimiters and dangerous control characters
const transcript_text = rawText
  .replace(/\{\{/g, '{ {')
  .replace(/\}\}/g, '} }')
  .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, ' ')
  .trim()
  .slice(0, 50000);

return [{ json: { transcript_text, file_name: fileName, file_id: fileId, mime_type: mimeType } }];

// SC-11: verify LLM endpoint is private/local before sending transcript data
// SC-11: Anthropic API — intentional use of hosted LLM; key validated at startup
if (!$env.ANTHROPIC_API_KEY) {
  throw new Error('ANTHROPIC_API_KEY is not set in n8n environment variables.');
}

const sanitized = $('Classify & SC-14 Sanitize').item.json;
const rosterRows = $('Fetch Roster').all();

// MED-1 / SC-19: roster must have active members before proceeding
const teamMembers = rosterRows.filter(r => r.json.role !== 'client');
if (teamMembers.length === 0) {
  throw new Error('SC-19: Active team roster is empty — cannot process standup. Re-run Workflow 00 (Startup / Config Validation) to validate the roster.');
}

// Build roster name list (names only — no IDs, no roles — SC-03)
const rosterList = teamMembers.map(r => '- ' + r.json.name).join('\n');

// HIGH-1: extended SC-14 second pass — covers additional instruction-tuned model delimiters
// Strips both line-start and mid-line System:/SYSTEM: variants; covers Llama-3, Gemma, Qwen patterns
const safeTranscript = String(sanitized.transcript_text || '')
  .replace(/^(System:|SYSTEM:|###|\[INST\]|<\|im_start\|>|<\|end_of_turn\|>|<\|eot_id\|>|<s>|<\/s>|<\|begin_of_text\|>|<\|start_header_id\|>)/gm, '  ')
  .replace(/(System:|SYSTEM:)/g, '  ')
  .slice(0, 40000);

const today = new Date().toISOString().slice(0, 10);

const systemPrompt = [
  'You are a standup transcript analyzer. Extract structured meeting data.',
  'Write all summary fields in French.',
  '',
  'OUTPUT: respond with ONLY valid JSON — no markdown fences, no explanation, no trailing text.',
  '',
  'REQUIRED JSON SCHEMA:',
  '{',
  '  "standup_date": "YYYY-MM-DD",',
  '  "updates": [',
  '    {',
  '      "roster_name": "exact name from ROSTER LIST below",',
  '      "raw_text": "verbatim summary of what this person reported",',
  '      "feature_area": "primary feature or work area they mentioned (alphanumeric and spaces only)",',
  '      "has_blocker": true or false',
  '    }',
  '  ],',
  '  "feature_summaries": [',
  '    {',
  '      "feature_area": "same area name as used in updates",',
  '      "summary": "project-level progress summary for this area — NO names, NO pronouns, NO individual attribution"',
  '    }',
  '  ]',
  '}',
  '',
  'RULES (mandatory):',
  '1. Only include people from the ROSTER LIST below who spoke in the transcript.',
  '2. feature_summaries.summary must be 100% project-level — never attribute work to any individual.',
  '3. standup_date: infer from transcript context; default to ' + today + '.',
  '4. If content is garbled or no roster member can be attributed, use empty arrays for updates.',
  '5. feature_area must be simple words without special characters.',
  '',
  'ROSTER LIST (match only these exact names):',
  rosterList
].join('\n');

return [{ json: {
  model: $env.LLM_MODEL,
  max_tokens: 4096,
  temperature: 0.1,
  system: systemPrompt,
  messages: [
    { role: 'user', content: 'Extract standup data from this transcript:\n\n' + safeTranscript }
  ]
} }];

const response = $input.first().json;
const rosterRows = $('Fetch Roster').all();

// Parse LLM JSON output
let parsed;
try {
  const raw = String(response.choices?.[0]?.message?.content ?? '').trim();
  const jsonStr = raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '').trim();
  parsed = JSON.parse(jsonStr);
} catch (e) {
  throw new Error('F-04.3: LLM output is not valid JSON — transcript may be garbled. Error: ' + e.message);
}

if (!Array.isArray(parsed.updates))          parsed.updates          = [];
if (!Array.isArray(parsed.feature_summaries)) parsed.feature_summaries = [];
if (!parsed.standup_date || !/^\d{4}-\d{2}-\d{2}$/.test(parsed.standup_date)) {
  parsed.standup_date = new Date().toISOString().slice(0, 10);
}

// Build normalised name → discord_id map (team members only)
const normalize = s => String(s).normalize('NFKD').replace(/[^A-Za-z0-9]/g, '').toLowerCase();
const rosterMap = {};
for (const r of rosterRows) {
  if (r.json.role !== 'client') {
    rosterMap[normalize(r.json.name)] = r.json.discord_id;
  }
}

// Match each update to a discord_id
const matchedUpdates = [];
for (const u of parsed.updates) {
  const discordId = rosterMap[normalize(String(u.roster_name || ''))];
  if (!discordId) continue;

  const area = String(u.feature_area || 'general')
    .replace(/[^A-Za-z0-9 \-_]/g, '').slice(0, 100).trim() || 'general';

  // SC-14: sanitise raw_text before storing in standup_records
  const rawText = String(u.raw_text || '')
    .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, ' ')
    .trim().slice(0, 4000);
  if (!rawText) continue;

  matchedUpdates.push({
    discord_id: discordId,
    standup_date: parsed.standup_date,
    raw_text: rawText,
    feature_area: area,
    has_blocker: Boolean(u.has_blocker)
  });
}

// F-04.3: nothing attributable → surface error
if (matchedUpdates.length === 0) {
  throw new Error(
    'F-04.3: No attributable updates found. Transcript may be garbled, incomplete, ' +
    'or contain no names matching the active roster.'
  );
}

// Normalised name list for HIGH-1 post-LLM scan
const normalizedRosterNames = Object.keys(rosterMap).filter(n => n.length >= 3);

// Word-boundary helper (same logic as F-08 Pattern Audit)
const hasWordBoundary = (haystack, needle) => {
  let idx = 0;
  while ((idx = haystack.indexOf(needle, idx)) !== -1) {
    const pre  = idx === 0 || !/[a-z0-9]/.test(haystack[idx - 1]);
    const post = idx + needle.length >= haystack.length || !/[a-z0-9]/.test(haystack[idx + needle.length]);
    if (pre && post) return true;
    idx++;
  }
  return false;
};

// Sanitise feature_summaries — strip injection delimiters, apply HIGH-1 roster-name scan
const matchedSummaries = parsed.feature_summaries
  .filter(s => s.feature_area && s.summary)
  .map(s => ({
    feature_area: String(s.feature_area)
      .replace(/[^A-Za-z0-9 \-_]/g, '').slice(0, 100).trim() || 'general',
    summary: String(s.summary)
      .replace(/^(System:|SYSTEM:|###|\[INST\])/gm, '  ')
      .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, ' ')
      .trim().slice(0, 2000)
  }))
  .filter(s => s.feature_area && s.summary)
  .map(s => {
    // HIGH-1: if a roster name appears in a summary, replace with safe fallback
    // F-08 will do a full boundary audit on the combined text regardless
    const summaryNorm = normalize(s.summary);
    const hasName = normalizedRosterNames.some(normName => {
      const parts = normName.split(/(?=[A-Z])/).join(' ').split(/\s+/).filter(p => p.length >= 3);
      return parts.some(part => hasWordBoundary(summaryNorm, part));
    });
    if (hasName) {
      return {
        feature_area: s.feature_area,
        summary: 'Work on the ' + s.feature_area + ' feature progressed this standup period.'
      };
    }
    return s;
  });

// Fallback: if LLM produced no summaries, create a minimal project-level one
if (matchedSummaries.length === 0) {
  matchedSummaries.push({
    feature_area: 'general',
    summary: 'Standup completed. Feature areas not specified in this transcript.'
  });
}

return [{ json: {
  standup_date: parsed.standup_date,
  updates: matchedUpdates,
  feature_summaries: matchedSummaries
} }];

// HIGH-2: duplicate check removed — ON CONFLICT (discord_id, standup_date) DO NOTHING
// is the idempotency guarantee. Date-only pre-check would block legitimate partial transcripts.
const validated = $('Validate & Match Roster').item.json;
const updates = validated.updates;

if (!updates || updates.length === 0) {
  throw new Error('F-04: No matched updates to insert — should have been caught earlier.');
}

// Multi-row parameterized INSERT (no user data in query string — only $N placeholders)
const params = [];
const placeholders = updates.map((u, i) => {
  const b = i * 5;
  params.push(
    u.discord_id,
    u.standup_date,
    u.raw_text,
    u.feature_area,
    u.has_blocker
  );
  return `($${b+1}, $${b+2}::DATE, $${b+3}, $${b+4}, $${b+5})`;
});

const standup_query = [
  'INSERT INTO pipemind.standup_records (discord_id, standup_date, raw_text, feature_area, has_blocker)',
  'VALUES ' + placeholders.join(', '),
  'ON CONFLICT (discord_id, standup_date) DO NOTHING;'
].join('\n');

return [{ json: { standup_query, standup_params: params } }];

const validated = $('Validate & Match Roster').item.json;
const summaries = validated.feature_summaries;
const standupDate = validated.standup_date;

// Combine feature summaries into one text for F-08 boundary audit
// Format: "feature_area: summary" per line, separated by double newline
// CRIT-1: Build Signal Upsert will parse f08Result.draft_text back into this format
const combined = summaries
  .map(s => s.feature_area + ': ' + s.summary)
  .join('\n\n');

if (!String($env.F08_WORKFLOW_ID || '').trim()) {
  throw new Error('F-04: n8n variable F08_WORKFLOW_ID is not set. Set it in n8n Settings → Variables after importing workflows.');
}

return [{ json: {
  draft_text: combined,
  content_type: 'standup_summary',
  feature_tag: 'F-04',
  standup_date: standupDate
} }];

const f08Result = $input.first().json;
if (!f08Result.boundary_audit_passed) {
  throw new Error('F-04: F-08 boundary audit did not return boundary_audit_passed. Cannot upsert project_signals.');
}

const buildInput = $('Build F-08 Input').item.json;
const standupDate = buildInput.standup_date;
const validated   = $('Validate & Match Roster').item.json;

// CRIT-1: use f08Result.draft_text (possibly rewritten by F-08 Ollama) — never the originals
// The combined text format is "feature_area: summary" per block, joined by double newline
const cleanSummaries = f08Result.draft_text
  .split('\n\n')
  .map(block => {
    const colonIdx = block.indexOf(': ');
    if (colonIdx === -1) return null;
    return {
      feature_area: block.slice(0, colonIdx)
        .replace(/[^A-Za-z0-9 \-_]/g, '').slice(0, 100).trim(),
      summary: block.slice(colonIdx + 2).trim().slice(0, 2000)
    };
  })
  .filter(s => s && s.feature_area && s.summary);

if (cleanSummaries.length === 0) {
  throw new Error('F-04: No valid feature summaries after F-08 boundary rewrite. Cannot upsert project_signals.');
}

// Derive has_blocker per feature area from standup updates (area-level, not person-level — SC-03)
const blockerByArea = {};
for (const u of (validated.updates || [])) {
  if (u.has_blocker) blockerByArea[u.feature_area] = true;
}

// Multi-row parameterized UPSERT (no user data in query string — only $N placeholders)
// F-14.5: newer primary signal wins (WHERE clause enforces this)
const params = [];
const placeholders = cleanSummaries.map((s, i) => {
  const b = i * 4;
  params.push(
    s.feature_area,
    s.summary,
    Boolean(blockerByArea[s.feature_area]),
    standupDate + 'T00:00:00Z'
  );
  return `($${b+1}, $${b+2}, $${b+3}, 'standup', $${b+4}::TIMESTAMPTZ)`;
});

const signal_query = [
  'INSERT INTO pipemind.project_signals (feature_area, status_summary, has_blocker, source, last_primary_signal_at)',
  'VALUES ' + placeholders.join(', '),
  'ON CONFLICT (feature_area) DO UPDATE SET',
  '  status_summary          = EXCLUDED.status_summary,',
  '  has_blocker             = EXCLUDED.has_blocker,',
  '  source                  = \'standup\',',
  '  last_primary_signal_at  = EXCLUDED.last_primary_signal_at,',
  '  updated_at              = now()',
  'WHERE pipemind.project_signals.last_primary_signal_at IS NULL',
  '   OR EXCLUDED.last_primary_signal_at > pipemind.project_signals.last_primary_signal_at;'
].join('\n');

return [{ json: { signal_query, signal_params: params } }];
